def average(xs):
    if not xs:
        return 0.0
    return sum(xs) / len(xs)

def parse_int(s):
    try:
        return int(s)
    except ValueError:
        return None

def maximum(xs):
    m = xs[0]
    for x in xs:
        if x > m:
            m = x
    return m

